---@class StructActLotteryInfo
local StructActLotteryInfo = LxClass("StructActLotteryInfo", nil)
function StructActLotteryInfo:StructActLotteryInfo()
	---@type number 活动 sid
	self.sid = 0
	---@type number 当前轮次
	self.round = 0
	---@type StructLotteryData[]
	self.lotteryDatas = {}
	---@type number 剩余的免费抽奖次数
	self.freeCount = 0
	---@type number 剩余的钻石抽奖次数
	self.diamondCount = 0
	---@type number 今日总抽奖次数
	self.tolCount = 0
end

function StructActLotteryInfo:CreateByPb(pb)
	self.sid = pb.sid
	self.round = pb.round

	local lotteryDatas = {}
	for i,v in ipairs(pb.lotteryDatas) do
		local data = StructLotteryData:New()
		data:CreateByPb(v)
		table.insert(lotteryDatas,data)
	end
	self.lotteryDatas = lotteryDatas
	self.freeCount = pb.freeCount
	self.diamondCount = pb.diamondCount
	self.tolCount = pb.tolCount
end

function StructActLotteryInfo:SetActLotteryData(data)
	self.freeCount = data.freeCount
	self.diamondCount = data.diamondCount
	self.tolCount = data.tolCount

	self:SetLotteryData(data.lotteryData)
end

function StructActLotteryInfo:SetLotteryData(pb)
	local lotteryData = StructLotteryData:New()
	lotteryData:CreateByPb(pb)

	local len = #self.lotteryDatas
	if len < 1 then len = 1 end
	self.lotteryDatas[len] = lotteryData
end

function StructActLotteryInfo:CheckHasFree()
	return self.freeCount > 0
end

function StructActLotteryInfo:GetCurLotteryData()
	local lotteryDatas = self.lotteryDatas
	local len = #lotteryDatas
	return lotteryDatas[len]
end

return StructActLotteryInfo